// Parse the Config tab into a creator URL list.
const rows = items.map(i => i.json);
const config = {};
for (const r of rows) {
  const key = r['A'] || r['key'];
  const val = r['B'] || r['value'];
  if (key) config[key] = val || '';
}
const raw = config['linkedin_creators'] || '';
const perCreator = parseInt(config['linkedin_posts_per_creator'] || '5', 10);
const urls = raw.split('\n').map(s => s.trim()).filter(Boolean);
return urls.map(url => ({ json: { profileUrl: url, maxPosts: perCreator } }));

// Normalize Apify output into the shape /api/intel/ingest expects.
// Apify actors return slightly different field names depending on the
// actor version — adjust the field mapping below if your actor differs.
const out = [];
for (const item of items) {
  const post = item.json;
  const creatorName = post.author_name || post.authorName || post.profile_name || 'linkedin';
  const creatorUrl = post.author_profile_url || post.authorProfileUrl || post.profile_url || '';
  const url = post.post_url || post.postUrl || post.url || '';
  const text = post.text || post.post_text || post.content || '';
  const postedAt = post.posted_at || post.postedAt || post.date || '';
  const reactions = Number(post.reactions || post.likes || 0);
  const comments = Number(post.comments || post.comment_count || 0);
  if (!url || !text) continue;
  out.push({
    json: {
      creator_url: creatorUrl,
      creator_name: creatorName,
      posted_at: postedAt,
      url,
      text,
      reactions,
      comments,
      type: 'linkedin'
    }
  });
}
return out;
